import type { Metadata } from 'next';
import Link from 'next/link';
import { notFound } from 'next/navigation';
import type { JsonPlaceholderPost, JsonPlaceholderComment } from '@/lib/blog';
import { getAllPosts, getCommentsByPostId, getPostById } from '@/lib/blog';

export const revalidate = 300;

interface BlogPostPageProps {
  params: Promise<{
    id: string;
  }>;
}

interface BlogPostMetadataProps {
  params: Promise<{
    id: string;
  }>;
}

export async function generateStaticParams(): Promise<Array<{ id: string }>> {
  const posts = await getAllPosts(revalidate);

  return posts.slice(0, 10).map((post) => ({
    id: String(post.id),
  }));
}

export async function generateMetadata(
  { params }: BlogPostMetadataProps
): Promise<Metadata> {
  const { id } = await params;
  const post = await getPostById(id, revalidate);

  if (!post) {
    return {
      title: 'Post not found',
    };
  }

  return {
    title: post.title,
    description: post.body.slice(0, 160),
    openGraph: {
      title: post.title,
      description: post.body.slice(0, 160),
    },
  };
}

export default async function BlogPostPage({ params }: BlogPostPageProps) {
  const { id } = await params;

  const [post, comments] = await Promise.all([
    getPostById(id, revalidate),
    getCommentsByPostId(id, revalidate),
  ]);

  if (!post) {
    notFound();
  }

  return (
    <article className="page-shell">
      <Link className="button button-secondary" href="/blog">
        Back
      </Link>

      <h2>{post.title}</h2>
      <p>{post.body}</p>

      <h3>Comments ({comments.length})</h3>
      <div className="comments">
        {comments.map((comment) => (
          <div key={comment.id} className="comment">
            <h4>{comment.name}</h4>
            <p>{comment.body}</p>
            <small>By: {comment.email}</small>
          </div>
        ))}
      </div>
    </article>
  );
}

