import { NextResponse } from 'next/server';
import type { ApiPost, ApiPostInput } from '@/lib/blog';

const posts: ApiPost[] = [
  { id: 1, title: 'First Post', content: 'This is the first post' },
  { id: 2, title: 'Second Post', content: 'This is the second post' },
];

export async function GET() {
  return NextResponse.json<ApiPost[]>(posts, { status: 200 });
}

export async function POST(request: Request) {
  const body = (await request.json()) as Partial<ApiPostInput>;
  const { title, content } = body;

  if (!title || !content) {
    return NextResponse.json({ error: 'Title and content are required' }, { status: 400 });
  }

  const newPost: ApiPost = {
    id: Date.now(),
    title,
    content,
    createdAt: new Date().toISOString(),
  };

  return NextResponse.json<ApiPost>(newPost, { status: 201 });
}

